mapper.select:
SELECT b.*, c.name as categoryName, u.username as sellerName FROM book b LEFT JOIN book_category c ON b.category_id = c.category_id LEFT JOIN user u ON b.seller_id = u.user_id WHERE b.deleted = 0
AND b.title LIKE CONCAT('%', #{title}, '%')
AND b.category_id = #{categoryId}
AND b.status = #{status}
AND b.seller_id = #{sellerId}
ORDER BY b.create_time DESC

mapper.update:
UPDATE book
SET view_count = view_count + 1
WHERE book_id = #{bookId}
